typedef enum logic[4:0] { EXC_A = 0, EXC_B = 1, EXC_C = 2 } exc_code_t;
function exc_code_t func1(bit inx);
  exc_code_t rVal;
  case(inx) 1: rVal = EXC_C; 0: rVal = EXC_B; default: rVal = EXC_A; endcase
  return(rVal);
endfunction
exc_code_t exc_code;
initial exc_code = func1(1'b1);
